-- RealityDB FinTech Template | Seed: 42 | ~180 rows
-- Lifecycle: reversed/failed transactions → settled_at = NULL
-- Temporal: settled_at > created_at
-- Weights: account_type checking=50% savings=30% investment=15% credit=5% | txn_status completed=70% pending=15% failed=10% reversed=5%

CREATE TABLE customers (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), name TEXT NOT NULL, email TEXT NOT NULL, phone TEXT, risk_score TEXT NOT NULL, kyc_status TEXT NOT NULL, created_at TIMESTAMP NOT NULL);
CREATE TABLE accounts (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), customer_id UUID NOT NULL REFERENCES customers(id), account_type TEXT NOT NULL, balance NUMERIC(12,2) NOT NULL, currency TEXT NOT NULL DEFAULT 'USD', status TEXT NOT NULL, created_at TIMESTAMP NOT NULL);
CREATE TABLE transactions (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), account_id UUID NOT NULL REFERENCES accounts(id), type TEXT NOT NULL, amount NUMERIC(12,2) NOT NULL, status TEXT NOT NULL, description TEXT, settled_at TIMESTAMP, created_at TIMESTAMP NOT NULL);
CREATE TABLE fraud_alerts (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), transaction_id UUID NOT NULL REFERENCES transactions(id), severity TEXT NOT NULL, type TEXT NOT NULL, status TEXT NOT NULL, resolved_at TIMESTAMP, created_at TIMESTAMP NOT NULL);




